const minMag = Number(flow.get('MIN_MAGNITUDE') || 2.5);
const fc = msg.payload;
if (!fc || fc.type !== 'FeatureCollection' || !Array.isArray(fc.features)) {
    node.warn('USGS: unexpected payload shape');
    return null;
}

function fmt(feature) {
    const p = feature.properties || {};
    const depthKm = (feature.geometry && feature.geometry.coordinates && feature.geometry.coordinates[2]) || 0;
    const when = p.time ? new Date(p.time).toISOString() : '';
    feature.properties = {
        ...p,
        callsign: p.title || `M ${p.mag} earthquake`,
        remarks: `M${p.mag} at ${p.place || 'unknown'} (depth ${depthKm.toFixed(1)} km) ${when} ${p.url || ''}`.trim()
    };
    return feature;
}

const filtered = fc.features.filter(f => (f.properties && typeof f.properties.mag === 'number' && f.properties.mag >= minMag));
msg.payload = {
    type: 'FeatureCollection',
    features: filtered.map(fmt)
};
return msg;
